+        assert_eq!(ErrorCategory::Wezterm, ErrorCategory::Wezterm);
+        assert_ne!(ErrorCategory::Wezterm, ErrorCategory::Storage);
+        assert_ne!(ErrorCategory::Config, ErrorCategory::Internal);
+    }
